import axios from 'axios';
import { BASE_URL } from './helpers';

// ==================== Types ====================

export interface Series {
  id: string;
  name: string;
  description: string;
  concept: string;
  metadata: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

export interface Character {
  id: string;
  series_id: string;
  name: string;
  description: string;
  voice: string;
  /** UUID FK to media_items — use metadata.reference_image_url for display */
  reference_image_media_id?: string | null;
  metadata: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

export type EpisodeStatus = 'draft' | 'generating' | 'complete' | 'failed';

export interface EpisodeMetadata {
  status?: EpisodeStatus;
  run_id?: string;
  clip_id?: string;
  character_ids?: string[];
  initial_context?: string;
  error?: string;
  [key: string]: unknown;
}

export interface Episode {
  id: string;
  series_id: string;
  episode_number: number;
  title: string;
  synopsis: string;
  prev_episode_summary: string;
  metadata: EpisodeMetadata;
  created_at: string;
  updated_at: string;
}

/** Convenience: get the display URL for a character's reference image */
export function characterImageUrl(char: Character): string | undefined {
  const url = char.metadata?.reference_image_url;
  return typeof url === 'string' && url ? url : undefined;
}

// ==================== Series ====================

export const listSeries = (): Promise<Series[]> =>
  axios.get(`${BASE_URL}/series`).then((r) => {
    const data = r.data;
    return Array.isArray(data) ? data : (data?.items ?? []);
  });

export const getSeries = (id: string): Promise<Series> =>
  axios.get(`${BASE_URL}/series/${id}`).then((r) => r.data);

export const createSeries = (data: { name: string; concept: string; description?: string }): Promise<Series> =>
  axios.post(`${BASE_URL}/series`, {
    name: data.name,
    description: data.description ?? '',
    concept: data.concept,
    metadata: {},
  }).then((r) => r.data);

export const updateSeries = (
  id: string,
  data: Partial<Pick<Series, 'name' | 'description' | 'concept' | 'metadata'>>
): Promise<Series> =>
  axios.put(`${BASE_URL}/series/${id}`, data).then((r) => r.data);

export const deleteSeries = (id: string): Promise<void> =>
  axios.delete(`${BASE_URL}/series/${id}`).then(() => undefined);

// ==================== Characters ====================

export const listCharacters = (seriesId: string): Promise<Character[]> =>
  axios.get(`${BASE_URL}/characters`, { params: { series_id: seriesId } }).then((r) => {
    const data = r.data;
    return Array.isArray(data) ? data : (data?.items ?? []);
  });

export const createCharacter = (data: {
  series_id: string;
  name: string;
  description?: string;
  voice?: string;
  reference_image_media_id?: string;
  /** stored as metadata.reference_image_url for display */
  reference_image_url?: string;
}): Promise<Character> =>
  axios.post(`${BASE_URL}/characters`, {
    series_id: data.series_id,
    name: data.name,
    description: data.description ?? '',
    voice: data.voice ?? '',
    reference_image_media_id: data.reference_image_media_id ?? null,
    metadata: { reference_image_url: data.reference_image_url ?? '' },
  }).then((r) => r.data);

export const updateCharacter = (
  id: string,
  data: {
    name?: string;
    description?: string;
    voice?: string;
    reference_image_media_id?: string | null;
    /** stored as metadata.reference_image_url for display */
    reference_image_url?: string;
    metadata?: Record<string, unknown>;
  }
): Promise<Character> => {
  const payload: Record<string, unknown> = {};
  if (data.name !== undefined) payload.name = data.name;
  if (data.description !== undefined) payload.description = data.description;
  if (data.voice !== undefined) payload.voice = data.voice;
  if (data.reference_image_media_id !== undefined)
    payload.reference_image_media_id = data.reference_image_media_id;
  payload.metadata = {
    ...(data.metadata ?? {}),
    ...(data.reference_image_url !== undefined
      ? { reference_image_url: data.reference_image_url }
      : {}),
  };
  return axios.put(`${BASE_URL}/characters/${id}`, payload).then((r) => r.data);
};

export const deleteCharacter = (id: string): Promise<void> =>
  axios.delete(`${BASE_URL}/characters/${id}`).then(() => undefined);

// ==================== Episodes ====================

export const listEpisodes = (seriesId: string): Promise<Episode[]> =>
  axios.get(`${BASE_URL}/episodes`, { params: { series_id: seriesId } }).then((r) => {
    const data = r.data;
    return Array.isArray(data) ? data : (data?.items ?? []);
  });

export const createEpisode = (data: {
  series_id: string;
  episode_number: number;
  title?: string;
  synopsis?: string;
  metadata?: EpisodeMetadata;
}): Promise<Episode> =>
  axios.post(`${BASE_URL}/episodes`, {
    series_id: data.series_id,
    episode_number: data.episode_number,
    title: data.title ?? '',
    synopsis: data.synopsis ?? '',
    prev_episode_summary: '',
    metadata: data.metadata ?? {},
  }).then((r) => r.data);

export const updateEpisode = (
  id: string,
  data: Partial<Pick<Episode, 'title' | 'synopsis' | 'prev_episode_summary' | 'episode_number' | 'metadata'>>
): Promise<Episode> =>
  axios.put(`${BASE_URL}/episodes/${id}`, data).then((r) => r.data);

export const deleteEpisode = (id: string): Promise<void> =>
  axios.delete(`${BASE_URL}/episodes/${id}`).then(() => undefined);
